  1	/**
  2	 * Utilizes PatternFly for a responsive toolbar with theme toggling, help, and user logout functionality.
  3	 * It auto-detects theme preference, provides a dropdown for help and user actions, and manages session state for
  4	 * logout.
  5	 *
  6	 * @module appToolbar
  7	 */
  8	import React, { useEffect, useState } from 'react';
  9	import {
 10	  Dropdown,
 11	  DropdownItem,
 12	  Icon,
 13	  MenuToggle,
 14	  ToggleGroup,
 15	  ToggleGroupItem,
 16	  Toolbar,
 17	  ToolbarContent,
 18	  ToolbarGroup,
 19	  ToolbarItem
 20	} from '@patternfly/react-core';
 21	import { EllipsisVIcon, MoonIcon, QuestionCircleIcon, SunIcon } from '@patternfly/react-icons';
 22	import { useLogoutApi, useUserApi } from '../../hooks/useLoginApi';
 23	import '@patternfly/react-styles/css/components/Avatar/avatar.css';
 24	import './viewLayoutToolbar.css';
 25	import AboutModal from '../aboutModal/aboutModal';
 26	
 27	interface AppToolbarProps {
 28	  useLogout?: typeof useLogoutApi;
 29	  useUser?: typeof useUserApi;
 30	}
 31	
 32	const AppToolbar: React.FC<AppToolbarProps> = ({ useLogout = useLogoutApi, useUser = useUserApi }) => {
 33	  const { logout: onLogout } = useLogout();
 34	  const { getUser } = useUser();
 35	  const [userName, setUserName] = useState<string>();
 36	  const [helpOpen, setHelpOpen] = useState<boolean>(false);
 37	  const [aboutOpen, setAboutOpen] = useState<boolean>(false);
 38	  const [userDropdownOpen, setUserDropdownOpen] = useState<boolean>(false);
 39	  const [kebabDropdownOpen, setKebabDropdownOpen] = useState<boolean>(false);
 40	  const [isDarkTheme, setIsDarkTheme] = useState(
 41	    window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches
 42	  );
 43	
 44	  useEffect(() => {
 45	    getUser().then(username => setUserName(username));
 46	    // eslint-disable-next-line react-hooks/exhaustive-deps
 47	  }, []);
 48	
 49	  const applyTheme = isDark => {
 50	    const htmlElement = document.getElementsByTagName('html')[0];
 51	    if (htmlElement) {
 52	      if (isDark) {
 53	        htmlElement.classList.add('pf-v6-theme-dark');
 54	      } else {
 55	        htmlElement.classList.remove('pf-v6-theme-dark');
 56	      }
 57	    }
 58	  };
 59	  applyTheme(isDarkTheme);
 60	
 61	  const onAbout = () => setAboutOpen(true);
 62	
 63	  const onAboutClose = () => setAboutOpen(false);
 64	
 65	  const onHelpSelect = (
 66	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 67	    _value: string | number | undefined
 68	  ) => {
 69	    setHelpOpen(false);
 70	  };
 71	
 72	  const onUserDropdownSelect = (
 73	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 74	    _value: string | number | undefined
 75	  ) => {
 76	    setUserDropdownOpen(false);
 77	  };
 78	
 79	  return (
 80	    <React.Fragment>
 81	      <Toolbar id="toolbar" isFullHeight isStatic>
 82	        <ToolbarContent>
 83	          <ToolbarGroup
 84	
 85	            align={{ default: 'alignRight' }}
 86	            gap={{ default: 'spacerNone', md: 'spacerMd' }}
 87	          >
 88	            <ToolbarGroup visibility={{ default: 'hidden', lg: 'visible' }}>
 89	              <ToolbarItem>
 90	                <ToggleGroup aria-label="Dark theme toggle group">
 91	                  <ToggleGroupItem
 92	                    aria-label="light theme toggle"
 93	                    icon={
 94	                      <Icon size="md">
 95	                        <SunIcon />
 96	                      </Icon>
 97	                    }
 98	                    isSelected={!isDarkTheme}
 99	                    onChange={() => {
100	                      setIsDarkTheme(false);
101	                      applyTheme(false);
102	                    }}
103	                  />
104	                  <ToggleGroupItem
105	                    aria-label="dark theme toggle"
106	                    icon={
107	                      <Icon size="md">
108	                        <MoonIcon />
109	                      </Icon>
110	                    }
111	                    isSelected={isDarkTheme}
112	                    onChange={() => {
113	                      setIsDarkTheme(true);
114	                      applyTheme(true);
115	                    }}
116	                  />
117	                </ToggleGroup>
118	              </ToolbarItem>
119	              <ToolbarItem>
120	                <Dropdown
121	                  popperProps={{ position: 'right' }}
122	                  onSelect={onHelpSelect}
123	                  onOpenChange={(isOpen: boolean) => setHelpOpen(isOpen)}
124	                  isOpen={helpOpen}
125	                  toggle={toggleRef => (
126	                    <MenuToggle
127	                      aria-label="Toggle"
128	                      ref={toggleRef}
129	                      variant="plain"
130	                      onClick={() => setHelpOpen(prev => !prev)}
131	                      isExpanded={helpOpen}
132	                      data-ouia-component-id="help_menu_toggle"
133	                    >
134	                      <QuestionCircleIcon />
135	                    </MenuToggle>
136	                  )}
137	                >
138	                  <DropdownItem onClick={onAbout} value="about">
139	                    About
140	                  </DropdownItem>
141	                </Dropdown>
142	              </ToolbarItem>
143	            </ToolbarGroup>
144	            <ToolbarItem visibility={{ default: 'visible', lg: 'hidden' }}>
145	              <Dropdown
146	                isPlain
147	                popperProps={{ position: 'right' }}
148	                onSelect={onUserDropdownSelect}
149	                onOpenChange={(isOpen: boolean) => setKebabDropdownOpen(isOpen)}
150	                isOpen={kebabDropdownOpen}
151	                toggle={toggleRef => (
152	                  <MenuToggle
153	                    aria-label="Toggle"
154	                    ref={toggleRef}
155	                    variant="plain"
156	                    onClick={() => setKebabDropdownOpen(prev => !prev)}
157	                    isExpanded={kebabDropdownOpen}
158	                    style={{ width: 'auto' }}
159	                    data-ouia-component-id="user_dropdown_button"
160	                  >
161	                    <EllipsisVIcon />
162	                  </MenuToggle>
163	                )}
164	              >
165	                <DropdownItem value="logout" onClick={onLogout} data-ouia-component-id="logout">
166	                  Logout
167	                </DropdownItem>
168	              </Dropdown>
169	            </ToolbarItem>
170	          </ToolbarGroup>
171	          <ToolbarItem visibility={{ default: 'hidden', lg: 'visible' }}>
172	            <Dropdown
173	              onSelect={onUserDropdownSelect}
174	              onOpenChange={(isOpen: boolean) => setUserDropdownOpen(isOpen)}
175	              isOpen={userDropdownOpen}
176	              toggle={toggleRef => (
177	                <MenuToggle
178	                  aria-label="Toggle"
179	                  ref={toggleRef}
180	                  variant="plain"
181	                  onClick={() => setUserDropdownOpen(prev => !prev)}
182	                  isExpanded={userDropdownOpen}
183	                  data-ouia-component-id="user_dropdown_button"
184	                >
185	                  <div className="quipucords-toolbar__user-dropdown">
186	                    <span className="pf-v6-c-avatar" />
187	                    {userName}
188	                  </div>
189	                </MenuToggle>
190	              )}
191	            >
192	              <DropdownItem value="logout" onClick={onLogout} data-ouia-component-id="logout">
193	                Logout
194	              </DropdownItem>
195	            </Dropdown>
196	          </ToolbarItem>
197	        </ToolbarContent>
198	      </Toolbar>
199	      <AboutModal isOpen={aboutOpen} onClose={onAboutClose} useUser={useUser} />
200	    </React.Fragment>
201	  );
202	};
203	
204	export { AppToolbar as default, AppToolbar, type AppToolbarProps };

